import socket
import threading
import pickle
import struct

class GameServer:
    def __init__(self, host='127.0.0.1', port=9999):
        self.host = host
        self.port = port
        self.server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server.bind((self.host, self.port))
        self.server.listen()
        self.clients = []
        self.positions = {}

    def handle_client(self, client):
        while True:
            try:
                data = client.recv(1024)
                if not data:
                    break
                player_id, position = pickle.loads(data)
                self.positions[player_id] = position
                self.broadcast(positions=self.positions)
            except:
                index = self.clients.index(client)
                self.clients.remove(client)
                client.close()
                break

    def broadcast(self, positions):
        for client in self.clients:
            try:
                data = pickle.dumps(positions)
                client.send(data)
            except:
                pass

    def receive_connections(self):
        while True:
            client, address = self.server.accept()
            print(f"New connection from {address}")
            self.clients.append(client)
            thread = threading.Thread(target=self.handle_client, args=(client,))
            thread.start()

    def run(self):
        print("Server started on port 9999")
        receive_thread = threading.Thread(target=self.receive_connections)
        receive_thread.start()
        while True:
            pass

if __name__ == "__main__":
    server = GameServer()
